import { useState } from "react";
import "./App.css";

export default function App() {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [toggleAlert, setToggleAlert] = useState(false);
    // const [main, setMain] = useState("");
    // const [sub, setSub] = useState("");
    // const [start, setStart] = useState(null);
    // const [deadline, setDeadLine] = useState(null);
    const [newTodo, setNewTodo] = useState({});
    const handleNewTodo = function (main, sub, start, deadline) {
        setNewTodo({ main, sub, start, deadline });
    };
    console.log(newTodo);

    const handleModal = function () {
        setIsModalOpen(!isModalOpen);
    };
    const handleAlert = function () {
        setToggleAlert(!toggleAlert);
    };

    return (
        <div className="App">
            <Header />
            <TodoBox handleModal={handleModal} />
            <Modal isModalOpen={isModalOpen} cl={"todo-modal"} setNewTodo={handleNewTodo}>
                <TodoModal handleModal={handleModal} />
            </Modal>
            <Modal isModalOpen={toggleAlert} cl={"alert-modal"}>
                <AlertModal handleAlert={handleAlert} />
            </Modal>
        </div>
    );
}
const Header = function () {
    return (
        <>
            <header className="header">
                <h1>Todoアプリ</h1>
            </header>
        </>
    );
};
const TodoBox = function ({ handleModal }) {
    return (
        <>
            <div className="todo-box">
                <Card cl={"add-card"}>
                    <AddCard handleModal={handleModal} />
                </Card>
            </div>
        </>
    );
};
const Card = function ({ cl, children }) {
    return <div className={`${cl} card--layout`}>{children}</div>;
};
const AddCard = function ({ handleModal }) {
    return (
        <div className="add-card__box">
            <p className="add-card--text">追加</p>
            <button type="button" className="add-card__btn" onClick={handleModal}>
                <svg
                    xmlns="http://www.w3.org/2000/svg"
                    viewBox="0 0 24 24"
                    fill="currentColor"
                    className="add-card__icon"
                >
                    <path
                        fill-rule="evenodd"
                        d="M12 3.75a.75.75 0 0 1 .75.75v6.75h6.75a.75.75 0 0 1 0 1.5h-6.75v6.75a.75.75 0 0 1-1.5 0v-6.75H4.5a.75.75 0 0 1 0-1.5h6.75V4.5a.75.75 0 0 1 .75-.75Z"
                        clip-rule="evenodd"
                    />
                </svg>
            </button>
        </div>
    );
};
// const TodoCard = function () {
//     return (
//         <>
//             `
//             <div class="todo-card card--layout" data-id="${id}" data-status="${status}">
//                 <select class="todo-card__select">
//                     <option value="yet">未着手</option>
//                     <option value="in-progress">進行中</option>
//                     <option value="done">完了</option>
//                 </select>
//                 <h3>${main}</h3>
//                 <h5>${sub}</h5>
//                 <p>開始:${start}</p>
//                 <p>期限:${deadline}</p>
//                 <button type="button" class="todo--delete">
//                     &times;
//                 </button>
//             </div>
//             `;
//         </>
//     );
// };
const Modal = function ({ isModalOpen, cl, children }) {
    return (
        <>
            <div className={isModalOpen ? `${cl}` : "hidden"}>{children}</div>
        </>
    );
};
const TodoModal = function ({ handleModal, handleNewTodo }) {
    const [main, setMain] = useState("");
    const [sub, setSub] = useState("");
    const [start, setStart] = useState(null);
    const [deadline, setDeadLine] = useState(null);

    return (
        <>
            <button type="button" className="todo-modal--close" onClick={handleModal}>
                &times;
            </button>
            <div className="input">
                <input
                    type="text"
                    className="input--main"
                    placeholder="main"
                    onChange={(e) => setMain(e.target.value)}
                />
                <input type="text" className="input--sub" placeholder="sub" onChange={(e) => setSub(e.target.value)} />
                <input
                    type="date"
                    className="input--start"
                    placeholder="start"
                    onChange={(e) => setStart(e.target.value)}
                />
                <input
                    type="date"
                    className="input--deadline"
                    placeholder="deadline"
                    onChange={(e) => setDeadLine(e.target.value)}
                />
            </div>
            <button type="button" className="add-new-todo-btn" onClick={handleNewTodo(main, sub, start, deadline)}>
                追加
            </button>
        </>
    );
};
const AlertModal = function ({ handleAlert }) {
    return (
        <>
            <button type="button" class="alert-modal--close" onClick={handleAlert}>
                &times;
            </button>
        </>
    );
};
